/* ── Tab Config ── */
const TABS: { key: Tab; label: string; icon: (color: string) => React.ReactNode }[] = [
  { key: "home", label: "Home", icon: (c) => <HomeIcon size={18} color={c} /> },
  { key: "market", label: "Market", icon: (c) => <ShopIcon size={18} color={c} /> },
  { key: "chat", label: "Chat", icon: (c) => <ChatDotsIcon size={18} color={c} /> },
  { key: "wallet", label: "Wallet", icon: (c) => <WalletIcon size={18} color={c} /> },
];

type BottomNavProps = {
  activeTab: Tab;
  isLoading?: boolean;
  onTabPress: (tab: Tab) => void;
};

export function BottomNav({ activeTab, isLoading = false, onTabPress }: BottomNavProps) {
  const { width } = useWindowDimensions();
  const loadingProgress = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (!isLoading) {
      loadingProgress.stopAnimation();
      loadingProgress.setValue(0);
      return;
    }

    const animation = Animated.loop(
      Animated.timing(loadingProgress, {
        toValue: 1,
        duration: 900,
        useNativeDriver: true,
      })
    );

    animation.start();

    return () => animation.stop();
  }, [isLoading, loadingProgress]);

  const loadingTranslateX = loadingProgress.interpolate({
    inputRange: [0, 1],
    outputRange: [-110, width],
  });

  return (
    <BlurView 
      intensity={100} 
      tint="dark" 
      style={[
        styles.container, 
        { backgroundColor: 'rgba(0, 0, 0, 0.92)' }
      ]}
    >
      {isLoading && (
        <Animated.View
          pointerEvents="none"
          style={[
            styles.loadingStroke,
            { transform: [{ translateX: loadingTranslateX }] },
          ]}
        />
      )}
      <View style={styles.tabRow}>
        {TABS.map((tab) => {
          const active = tab.key === activeTab;
          const color = active ? "#1B17B3" : "#FFFFFF"; 
          return (
            <Pressable
              key={tab.key}
              style={styles.tab}
              onPress={() => onTabPress(tab.key)}
              hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
            >
              {tab.icon(color)}
              <Text style={[styles.label, { color }]}>{tab.label}</Text>
            </Pressable>
          );
        })}
      </View>
    </BlurView>
  );
}

const NAV_HEIGHT = 80;

const styles = StyleSheet.create({
  container: {
    position: "absolute",
    bottom: 0,
    left: 0,
    right: 0,
    height: NAV_HEIGHT,
    borderTopWidth: 1,
    borderTopColor: "#262525",
    overflow: "hidden",
    zIndex: 20,
  },
  loadingStroke: {
    position: "absolute",
    top: 0,
    left: 0,
    width: 110,
    height: 2,
    borderRadius: 2,
    backgroundColor: "#1B17B3",
    shadowColor: "#1B17B3",
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0.9,
    shadowRadius: 8,
    elevation: 4,
  },
  tabRow: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    paddingHorizontal: 18,
    paddingTop: 12,
    height: 60,
  },
  tab: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
    gap: 4,
  },
  label: {
    fontFamily: "Ubuntu_400Regular",
    fontSize: 13,
    lineHeight: 15,
    letterSpacing: -0.26,
  },
});

export { NAV_HEIGHT };
